SELECT site_name
FROM mining_sites
WHERE capacity = (SELECT MAX(capacity) FROM mining_sites);

SELECT SUM(total_wait) AS total_wait_time
FROM mining_iterations
WHERE mine_site_id = 1;

SELECT MIN(allocation_date) AS first_allocation_date
FROM resource_allocation
WHERE site_id = 1;

SELECT MAX(t_place_gold - t_forage_gold) AS gold_difference
FROM mining_iterations
WHERE mine_site_id = 1;

SELECT 
  (SELECT AVG(average_extraction_rate) FROM performance_reports) AS average_rate,
  (SELECT COUNT(*) FROM safety_incidents) AS total_incidents;
